public function generateP4Command(array $arguments, bool $useClient = true): array
    {
        $p4Command = [$this->getP4Executable()];
        if ($this->getUser() !== null) {
            $p4Command[] = '-u';
            $p4Command[] = $this->getUser();
        }
        if ($useClient) {
            $p4Command[] = '-c';
            $p4Command[] = $this->getClient();
        }
        $p4Command[] = '-p';
        $p4Command[] = $this->getPort();

        return array_merge($p4Command, $arguments);
    }

private function buildUri(UriInterface $uri, array $config): UriInterface
    {
        if (isset($config['base_uri'])) {
            $uri = Psr7\UriResolver::resolve(Psr7\Utils::uriFor($config['base_uri']), $uri);
        }

        $idnOptions = Utils::normalizeIdnConversionOption($config['idn_conversion'] ?? null);
        if ($idnOptions !== null) {
            $uri = Utils::idnUriConvert($uri, $idnOptions);
        }

        return $uri->getScheme() === '' && $uri->getHost() !== '' ? $uri->withScheme('http') : $uri;
    }

private function generateAlpha3ToAlpha2Mapping(ArrayAccessibleResourceBundle $metadataBundle): array
    {
        $alpha3ToAlpha2 = [];

        foreach ($metadataBundle['alias']['language'] as $alias => $data) {
            $language = $data['replacement'];
            if (2 === \strlen($language) && 3 === \strlen($alias) && \in_array($data['reason'], ['overlong', 'bibliographic'], true)) {
                $alpha3ToAlpha2[$alias] = $language;
            }
        }

        asort($alpha3ToAlpha2);

        return $alpha3ToAlpha2;
    }

private function standardize(string $string): string
    {
        // transform CR or LF to CRLF
        $string = preg_replace('~=0D(?!=0A)|(?<!=0D)=0A~', '=0D=0A', $string);
        // transform =0D=0A to CRLF
        $string = str_replace(["\t=0D=0A", ' =0D=0A', '=0D=0A'], ["=09\r\n", "=20\r\n", "\r\n"], $string);

        return match ($string[-1] ?? '') {
            "\x09" => substr_replace($string, '=09', -1),
            "\x20" => substr_replace($string, '=20', -1),
            default => $string,
        };
    }

private function getEncoder(): ContentEncoderInterface
    {
        if ('8bit' === $this->encoding) {
            return self::$encoders[$this->encoding] ??= new EightBitContentEncoder();
        }

        if ('quoted-printable' === $this->encoding) {
            return self::$encoders[$this->encoding] ??= new QpContentEncoder();
        }

        if ('base64' === $this->encoding) {
            return self::$encoders[$this->encoding] ??= new Base64ContentEncoder();
        }

        return self::$encoders[$this->encoding];
    }
